                                                            <span>{m.role}</span>
                                                            <span className="font-mono text-slate-400">• {m.manDays || 0} WD</span>
                                                            {m.competencyCodes && <span className="font-mono text-teal-600 bg-teal-50 px-1 rounded">[{m.competencyCodes}]</span>}
                                                        </div>
                                                    </div>
                                                    <button onClick={(e) => { e.stopPropagation(); setAuditTeam(prev => prev.filter(x => x.id !== m.id)); }} className="text-slate-400 hover:text-red-500 opacity-0 group-hover:opacity-100"><Icon name="X" size={12}/></button>
                                                </div>
                                            ))}
                                        </div>

                                        {/* Inputs */}
                                        <div className="bg-gray-50 dark:bg-slate-800/50 p-2 rounded-lg border border-gray-100 dark:border-slate-800 space-y-2">
                                            <input className="w-full bg-white dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-md p-1.5 text-xs outline-none focus:border-orange-500" placeholder="Name" value={newMember.name} onChange={e => setNewMember({...newMember, name: e.target.value})} />
                                            <div className="flex gap-2">
                                                <select className="flex-[2] bg-white dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-md p-1.5 text-xs outline-none" value={newMember.role} onChange={e => setNewMember({...newMember, role: e.target.value as any})}>
                                                    <option value="Auditor">Auditor</option>
                                                    <option value="Lead Auditor">Lead</option>
                                                    <option value="Technical Expert">Tech</option>
                                                </select>
                                                <input className="flex-1 bg-white dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-md p-1.5 text-xs outline-none focus:border-orange-500 text-center" placeholder="Code" value={newMember.competencyCodes} onChange={e => setNewMember({...newMember, competencyCodes: e.target.value})} />
                                                <input className="w-14 bg-white dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-md p-1.5 text-xs outline-none focus:border-orange-500 text-center [appearance:textfield] [&::-webkit-outer-spin-button]:appearance-none [&::-webkit-inner-spin-button]:appearance-none" type="number" placeholder="WD" value={newMember.manDays} onChange={e => setNewMember({...newMember, manDays: parseFloat(e.target.value) || 0})} />
                                            </div>

                                            {/* REMOTE TOGGLE */}
                                            <button 
                                                onClick={() => setNewMember({...newMember, isRemote: !newMember.isRemote})}
                                                className={`w-full flex items-center justify-center gap-2 py-1.5 rounded-md text-xs font-bold transition-all border ${newMember.isRemote ? 'bg-purple-100 text-purple-700 border-purple-200 dark:bg-purple-900/30 dark:text-purple-300 dark:border-purple-800' : 'bg-white dark:bg-slate-900 text-slate-500 border-gray-200 dark:border-slate-700 hover:bg-gray-100'}`}
                                            >
                                                <Icon name={newMember.isRemote ? "UploadCloud" : "Building"} size={14} />
                                                <span>{newMember.isRemote ? "Remote / Online Audit" : "Onsite Audit"}</span>
                                            </button>

                                            <input className="w-full bg-white dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-md p-1.5 text-xs outline-none focus:border-orange-500" placeholder="Availability / Notes" value={newMember.availability} onChange={e => setNewMember({...newMember, availability: e.target.value})} />

                                            <button onClick={handleSaveMember} className="w-full bg-indigo-50 text-indigo-600 border border-indigo-100 hover:bg-indigo-100 rounded py-1 text-xs font-bold flex items-center justify-center gap-1">
                                                {editingMemberId ? "Update Member" : <><Icon name="Plus" size={12}/> Add Member</>}
                                            </button>
                                            {editingMemberId && <button onClick={() => { setEditingMemberId(null); setNewMember({name:"", role:"Auditor", competencyCodes:"", manDays:1, isRemote:false, availability:""}); }} className="w-full text-[9px] text-slate-400 underline">Cancel Edit</button>}
                                        </div>
                                    </div>
                                )}
                            </div>

                            {/* 4. PROCESS MAPPING (ALWAYS EXPANDED) */}
                            <div className="bg-white dark:bg-slate-900 rounded-xl border border-gray-200 dark:border-slate-800 overflow-hidden shadow-sm flex-1 flex flex-col min-h-0">
                                <div className="flex justify-between items-center p-3 border-b border-gray-100 dark:border-slate-800 bg-gray-50/50 dark:bg-slate-800/30">
                                    <h4 className="text-xs font-black text-slate-500 uppercase tracking-widest flex items-center gap-2">
                                        <Icon name="Tag" size={14}/> Process Mapping
                                    </h4>
                                </div>

                                <div className="p-3 pt-2 space-y-2">
                                    {processes.map(p => (
                                        <div key={p.id} className="p-2 bg-slate-50 dark:bg-slate-800 rounded-lg border border-gray-100 dark:border-slate-700 text-xs">
                                            <div className="font-bold text-slate-800 dark:text-slate-200 mb-1">{p.name}</div>
                                            <div className="flex gap-2">
                                                <input 
                                                    className="w-16 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-600 rounded p-1 text-[9px] font-mono text-center outline-none focus:ring-1 focus:ring-orange-500" 
                                                    placeholder="CODE"
                                                    value={p.competencyCode || ""}
                                                    onChange={(e) => updateProcessCode(p.id, e.target.value)}
                                                />
                                                <select 
                                                    className="flex-1 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-600 rounded p-1 text-[9px] text-slate-600 dark:text-slate-300 outline-none"
                                                    value={p.siteIds?.[0] || ""}
                                                    onChange={(e) => updateProcessSites(p.id, e.target.value ? [e.target.value] : [])}
                                                >
                                                    <option value="">All Sites</option>
                                                    {auditSites.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                                                </select>
                                            </div>
                                        </div>
                                    ))}
                                    {processes.length === 0 && (
                                        <div className="text-center py-4 text-slate-400 text-xs italic">
                                            No processes defined.
                                        </div>
                                    )}
                                </div>
                            </div>

                            <button onClick={handleGenerateSchedule} disabled={isGenerating} className={`w-full py-3 rounded-xl font-bold text-xs shadow-lg transition-all active:scale-95 flex items-center justify-center gap-2 mt-auto flex-shrink-0 ${!isGenerating ? "btn-shrimp text-white hover:shadow-indigo-500/40" : "bg-gray-200 dark:bg-slate-800 text-slate-400 cursor-not-allowed"}`}>
                                {isGenerating ? <Icon name="Loader" className="animate-spin" size={14}/> : <Icon name="Wand2" size={14}/>}
                                {isGenerating ? "AI Planning..." : "GENERATE SCHEDULE"}
                            </button>

                        </div>

                        {/* RIGHT: SCHEDULE TABLE & GENERATION OVERLAY */}
                        <div className="flex-1 bg-white dark:bg-slate-900 relative flex flex-col overflow-hidden">
                            {/* ... Content on the right side (AI logs, Table) remains unchanged ... */}

                            {/* --- AI GENERATION OVERLAY --- */}
                            {isGenerating && (
                                <div className="absolute inset-0 bg-white/95 dark:bg-slate-900/95 backdrop-blur-md z-50 flex flex-col items-center justify-center p-8 animate-in fade-in duration-300 rounded-2xl border border-white/20 dark:border-slate-800">
                                    <div className="w-full max-w-lg space-y-6">
                                        <div className="flex flex-col items-center">
                                            <div className="relative w-16 h-16 mb-4">
                                                <div className="absolute inset-0 border-4 border-orange-100 dark:border-slate-700 rounded-full"></div>
                                                <div className="absolute inset-0 border-t-4 border-orange-500 rounded-full animate-spin"></div>
                                                <Icon name="Session7_Compass" className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-orange-500" size={24}/>
                                            </div>
                                            <h3 className="text-xl font-black text-slate-800 dark:text-white animate-pulse">Designing Audit Plan...</h3>
                                            <p className="text-sm text-slate-500 dark:text-slate-400 font-mono mt-1">{genProgress}% Complete</p>
                                        </div>

                                        {/* Progress Bar */}
                                        <div className="w-full h-2 bg-gray-200 dark:bg-slate-800 rounded-full overflow-hidden">
                                            <div 
                                                className="h-full bg-gradient-to-r from-orange-500 to-amber-500 transition-all duration-300 ease-out" 
                                                style={{ width: `${genProgress}%` }}
                                            ></div>
                                        </div>

                                        {/* Logs Console */}
                                        <div className="w-full h-40 bg-black/5 dark:bg-black/30 rounded-xl border border-gray-200 dark:border-slate-800 p-4 font-mono text-xs overflow-y-auto custom-scrollbar shadow-inner">
                                            {genLogs.map((log, idx) => (
                                                <div key={idx} className="mb-1 text-slate-600 dark:text-slate-400 flex gap-2">
                                                    <span className="text-orange-400 select-none">&gt;</span>
                                                    <span>{log}</span>
                                                </div>
                                            ))}
                                            <div ref={logsEndRef} />
                                        </div>
                                    </div>
                                </div>
                            )}

                            <div className="flex-1 overflow-y-auto custom-scrollbar p-6">
                                {auditSchedule.length === 0 ? (
                                    <div className="h-full flex flex-col items-center justify-center text-slate-400">
                                        <Icon name="Session7_Compass" size={48} className="mb-4 opacity-20"/>
                                        <p className="font-bold text-slate-500">No Schedule Generated</p>
                                        <p className="text-xs mt-2">Setup resources and click Generate.</p>
                                    </div>
                                ) : (
                                    <div className="space-y-8 pb-16">
                                        <div className="flex items-center justify-between mb-4">
                                            <h3 className="text-lg font-bold text-slate-800 dark:text-white flex items-center gap-2">
                                                <Icon name="Session7_Compass" className="text-orange-500"/> Audit Agenda
                                            </h3>
                                            <span className="text-[10px] text-slate-400 italic">
                                                Drag column headers to sort & group data
                                            </span>
                                        </div>

                                        {/* Group by Day */}
                                        {[...new Set(auditSchedule.map(s => s.day))].sort().map(day => {
                                            const dayItems = auditSchedule.filter(s => s.day === day);
                                            const dateLabel = dayItems[0]?.date || `Day ${day}`;
                                            const daySchedule = getSortedSchedule(dayItems);
                                            const rowSpans = calculateRowSpans(daySchedule, agendaColumns);

                                            return (
                                                <div key={day} className="mb-8">
                                                    <h4 className="text-sm font-bold text-orange-600 dark:text-orange-400 bg-orange-50 dark:bg-orange-900/20 px-4 py-1.5 rounded-lg inline-block mb-4 shadow-sm border border-orange-100 dark:border-orange-800/50">
                                                        Day {day}: {dateLabel}
                                                    </h4>

                                                    <div className="overflow-x-auto rounded-xl border border-gray-100 dark:border-slate-800 shadow-sm">
                                                        <table className="w-full border-collapse text-left bg-white dark:bg-slate-900">
                                                            <thead>
                                                                <tr className="bg-gray-50 dark:bg-slate-800/50 border-b border-gray-100 dark:border-slate-800 text-[10px] uppercase tracking-wider text-slate-500 select-none">
                                                                    {agendaColumns.map(col => (
                                                                        <th 
                                                                            key={col} 
                                                                            className="p-3 font-bold border-r border-gray-100 dark:border-slate-800 cursor-move hover:bg-gray-100 dark:hover:bg-slate-700 transition-colors"
                                                                            draggable
                                                                            onDragStart={(e) => handleDragStart(e, col)}
                                                                            onDragOver={(e) => handleDragOver(e, col)}
                                                                            onDragEnd={handleDragEnd}
                                                                        >
                                                                            <div className="flex items-center gap-1">
                                                                                <Icon name="Grid" size={10} className="opacity-50"/>
                                                                                {COLUMN_LABELS[col]}
                                                                            </div>
                                                                        </th>
                                                                    ))}
                                                                </tr>
                                                            </thead>
                                                            <tbody className="text-xs divide-y divide-gray-100 dark:divide-slate-800/50">
                                                                {daySchedule.map((item: any, idx: number) => (
                                                                    <tr key={idx} className="hover:bg-orange-50/30 dark:hover:bg-slate-800/30 transition-colors">
                                                                        {agendaColumns.map((col, colIdx) => {
                                                                            // Calculate real index in original flattened array for update
                                                                            const realIndex = auditSchedule.indexOf(item); 
                                                                            const span = rowSpans[`${idx}_${colIdx}`];
                                                                            if (span === 0) return null; // Hidden cell due to merge

                                                                            return (
                                                                                <td 
                                                                                    key={col} 
                                                                                    rowSpan={span}
                                                                                    className="p-3 border-r border-gray-100 dark:border-slate-800 align-top bg-white dark:bg-slate-900"
                                                                                >
                                                                                    {col === 'timeSlot' && <span className="font-mono font-bold text-slate-600 dark:text-slate-400">{item.timeSlot}</span>}
                                                                                    {col === 'siteName' && <span className="text-slate-500">{item.siteName}</span>}

                                                                                    {/* INTERACTIVE AUDITOR CELL */}
                                                                                    {col === 'auditorName' && (
                                                                                        <div 
                                                                                            className="group/auditor cursor-pointer flex items-center gap-2 hover:bg-gray-50 dark:hover:bg-slate-800 p-1.5 rounded-lg transition-colors border border-transparent hover:border-gray-200 dark:hover:border-slate-700"
                                                                                            onClick={() => setReassignTarget({ rowIndex: realIndex, currentName: item.auditorName })}
                                                                                            title="Click to reassign auditor"
                                                                                        >
                                                                                            <span className="font-medium text-slate-700 dark:text-slate-300 group-hover/auditor:text-indigo-600 dark:group-hover/auditor:text-indigo-400">
                                                                                                {item.auditorName}
                                                                                            </span>
                                                                                            {item.isRemote && <span className="text-[8px] bg-purple-100 text-purple-600 px-1 rounded">R</span>}
                                                                                            <Icon name="Users" size={12} className="opacity-0 group-hover/auditor:opacity-100 text-indigo-400 transition-opacity"/>
                                                                                        </div>
                                                                                    )}

                                                                                    {col === 'processName' && (
                                                                                        <div className="font-bold text-indigo-600 dark:text-indigo-400 flex items-center gap-1">
                                                                                            <Icon name="Session11_GridAdd" size={12}/> 
                                                                                            {item.processName || "General"}
                                                                                        </div>
                                                                                    )}
                                                                                    {col === 'activity' && (
                                                                                        <div className="font-bold text-slate-800 dark:text-slate-200">
                                                                                            {item.activity}
                                                                                        </div>
                                                                                    )}
                                                                                    {col === 'clauseRefs' && (
                                                                                        item.clauseRefs && item.clauseRefs.length > 0 ? (
                                                                                            <div className="flex flex-wrap gap-1">
                                                                                                {item.clauseRefs.map((c: string) => (
                                                                                                    <span key={c} className="bg-slate-100 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 px-1.5 py-0.5 rounded text-[9px] font-mono text-slate-600 dark:text-slate-400">{c}</span>
                                                                                                ))}
                                                                                            </div>
                                                                                        ) : <span className="text-slate-300 text-[10px]">-</span>
                                                                                    )}
                                                                                </td>
                                                                            );
                                                                        })}
                                                                    </tr>
                                                                ))}
                                                            </tbody>
                                                        </table>
                                                    </div>
                                                </div>
                                            );
                                        })}
                                    </div>
                                )}
                            </div>

                            {/* EXPORT TOOLBAR - FIXED AT BOTTOM */}
                            {auditSchedule.length > 0 && (
                                <div className="flex-none p-4 border-t border-gray-100 dark:border-slate-800 bg-white dark:bg-slate-900 z-10 flex justify-end gap-2 shadow-inner">
                                    <button onClick={() => onExport && onExport('schedule', exportLanguage, 'docx', { columns: agendaColumns })} className="px-4 h-[40px] bg-blue-600 hover:bg-blue-700 text-white rounded-xl text-xs font-bold flex items-center justify-center gap-2 transition-all duration-300 active:scale-95 shadow-lg whitespace-nowrap">
                                        <Icon name="Download" />
                                        <span className="hidden md:inline">Export</span>
                                        <div className="lang-pill-container ml-1">
                                            <span onClick={(e) => { e.stopPropagation(); setExportLanguage('en'); }} className={`lang-pill-btn ${exportLanguage === 'en' ? 'lang-pill-active' : 'lang-pill-inactive'}`}>EN</span>
                                            <span onClick={(e) => { e.stopPropagation(); setExportLanguage('vi'); }} className={`lang-pill-btn ${exportLanguage === 'vi' ? 'lang-pill-active' : 'lang-pill-inactive'}`}>VI</span>
                                        </div>
                                    </button>
                                </div>
                            )}
                        </div>
                    </div>
                )}
            </div>

            {/* Smart Calendar Modal */}
            <GlassDatePicker 
                isOpen={isCalendarOpen} 
                onClose={() => setIsCalendarOpen(false)}
                selectedDates={safeAuditDates}
                onChange={handleUpdateDates}
            />

            {/* Auditor Reassignment Modal */}
            <Modal 
                isOpen={!!reassignTarget} 
                title="Select Auditor for this Activity" 
                onClose={() => setReassignTarget(null)}
            >
                <div className="space-y-3">
                    <p className="text-xs text-slate-500">
                        Current: <span className="font-bold text-slate-800 dark:text-white">{reassignTarget?.currentName}</span>
                    </p>
                    <div className="max-h-[300px] overflow-y-auto custom-scrollbar border rounded-xl dark:border-slate-800">
                        {auditTeam.map(member => (
                            <div 
                                key={member.id}
                                className={`p-3 flex items-center justify-between cursor-pointer hover:bg-gray-50 dark:hover:bg-slate-800 border-b border-gray-100 dark:border-slate-800 last:border-0 ${reassignTarget?.currentName === member.name ? 'bg-indigo-50 dark:bg-indigo-900/20' : ''}`}
                                onClick={() => {
                                    if (reassignTarget) {
                                        updateScheduleItem(reassignTarget.rowIndex, 'auditorName', member.name);
                                        updateScheduleItem(reassignTarget.rowIndex, 'isRemote', member.isRemote);
                                        setReassignTarget(null);
                                    }
                                }}
                            >
                                <div className="flex-1">
                                    <div className="font-bold text-sm text-slate-800 dark:text-slate-200">{member.name}</div>
                                    <div className="text-[10px] text-slate-500 mt-0.5 flex gap-2">
                                        <span className="bg-slate-100 dark:bg-slate-700 px-1.5 rounded">{member.role}</span>
                                        {member.competencyCodes && <span className="font-mono text-teal-600 dark:text-teal-400">[{member.competencyCodes}]</span>}
                                    </div>
                                </div>
                                {reassignTarget?.currentName === member.name && <Icon name="CheckThick" className="text-emerald-500" size={16}/>}
                            </div>
                        ))}
                    </div>
                </div>
            </Modal>
        </div>
    );
};

import React, { useRef, useState, useMemo } from 'react';
import { Icon, IconSelect, IconInput } from '../UI';
import { useUI } from '../../contexts/UIContext';
import { useAudit } from '../../contexts/AuditContext';
import { AuditSite } from '../../types';

interface AuditInfoFormProps {
    onAddNewStandard: () => void;
    onOpenIntegrity: () => void;
    onKnowledgeUpload: (e: React.ChangeEvent<HTMLInputElement>) => void;
    health: { isHealthy: boolean; score: number };
    auditFieldIconColor: string;
    standardOptions: { value: string; label: string }[];
}

// Internal Helper for TextAreas to match IconInput style
const IconTextArea = ({ icon, iconColor, placeholder, value, onChange, className = "", rows = 2 }: any) => (
    <div className={`relative group ${className}`}>
        <div className="absolute left-3 top-3 pointer-events-none transition-colors duration-300">
            <div className={iconColor}><Icon name={icon} size={16} /></div>
        </div>
        <textarea 
            placeholder={placeholder}
            value={value}
            onChange={onChange}
            rows={rows}
            className="w-full pl-10 pr-3 py-3 bg-gray-50 dark:bg-slate-950 border border-gray-100 dark:border-slate-800 rounded-xl text-sm font-normal text-slate-700 dark:text-slate-300 placeholder-gray-400 outline-none focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 transition-all shadow-sm hover:border-indigo-200 dark:hover:border-slate-600 hover:shadow-md dark:shadow-[inset_0_2px_4px_rgba(0,0,0,0.5)] resize-y min-h-[44px]"
        />
    </div>
);

// Helper for Mandatory Label
const LabelRequired = ({ text }: { text: string }) => (
    <label className="text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase px-1">
        {text} <span className="text-red-500" title="Required Field">*</span>
    </label>
);

export const AuditInfoForm: React.FC<AuditInfoFormProps> = ({
    onAddNewStandard, onOpenIntegrity, onKnowledgeUpload, 
    health, auditFieldIconColor, standardOptions
}) => {
    // Consume Context Directly
    const { 
        standardKey, setStandardKey, auditInfo, setAuditInfo, standards,
        knowledgeFileName, clearKnowledge,
        processes, activeProcessId, setActiveProcessId,
        addProcess, renameProcess, deleteProcess,
        auditTypeOptions,
        auditSites, setAuditSites,
        auditTeam // Needed for Total WD calculation
    } = useAudit();

    const { showToast } = useUI();
    const fileInputRef = useRef<HTMLInputElement>(null);
    const processInputRef = useRef<HTMLInputElement>(null);
    const listRef = useRef<HTMLDivElement>(null); 
    const skipBlurRef = useRef(false);

    const [inputValue, setInputValue] = useState(""); 
    const [editingProcessId, setEditingProcessId] = useState<string | null>(null);
    const [editName, setEditName] = useState("");
    const [isProcessMenuOpen, setIsProcessMenuOpen] = useState(false);
    const [isCreating, setIsCreating] = useState(false);

    // Computed Logic
    const hasSource = !!knowledgeFileName;
    const isStandardSelected = !!standardKey && standardKey !== "ADD_NEW";
    const sourceIcon = hasSource ? "BookOpen" : "Book";

    const is27001 = useMemo(() => standardKey && standards[standardKey]?.name.includes("27001"), [standardKey, standards]);

    // Calculate Total Man Days
    const totalManDays = useMemo(() => {
        return auditTeam.reduce((acc, m) => acc + (m.manDays || 0), 0);
    }, [auditTeam]);

    let sourceColor = "text-gray-300 dark:text-slate-600"; 
    let sourceTooltip = "Please select an ISO Standard first to enable document upload.";
    let cursorClass = "cursor-not-allowed";

    if (hasSource) {
        sourceColor = "text-emerald-500 drop-shadow-sm";
        sourceTooltip = `Source Attached: ${knowledgeFileName}. Click to Replace.`;
        cursorClass = "cursor-pointer";
    } else if (isStandardSelected) {
        sourceColor = `${auditFieldIconColor} hover:text-indigo-600 dark:hover:text-indigo-300`;
        sourceTooltip = "Click to upload Source PDF or Word (DOCX) for better accuracy";
        cursorClass = "cursor-pointer hover:scale-110 active:scale-95";
    }

    const handleIconClick = () => {
        if (!isStandardSelected) return;
        if (fileInputRef.current) fileInputRef.current.click();
    };

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files.length > 0) {
            onKnowledgeUpload(e);
            e.target.value = '';
        }
    };

    // --- TOTAL SITES LOGIC ---
    const handleTotalSitesChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const val = parseInt(e.target.value) || 0;
        const diff = val - auditSites.length;

        if (diff > 0) {
            // Add new empty sites
            const newSites: AuditSite[] = [];
            for (let i = 0; i < diff; i++) {
                newSites.push({
                    id: `site_auto_${Date.now()}_${i}`,
                    name: `Site ${auditSites.length + i + 1}`,
                    address: "",
                    scope: "",
                    isMain: false,
                    employeeCount: 0
                });
            }
            setAuditSites([...auditSites, ...newSites]);
        } else if (diff < 0) {
            // Remove last sites (Simple trim)
            const remaining = auditSites.slice(0, val);
            setAuditSites(remaining);
        }
    };

    // --- INPUT HANDLER ---
    const handleAddKeyDown = (e: React.KeyboardEvent) => {
        if (e.key === 'Enter') {
            e.preventDefault();
            const trimmed = inputValue.trim();
            if (trimmed) {
                const existing = processes.find(s => s.name.toLowerCase() === trimmed.toLowerCase());
                if (existing) {
                    setActiveProcessId(existing.id);
                    showToast(`Switched to: ${existing.name}`);
                    setIsCreating(false); 
                    setInputValue("");
                    setIsProcessMenuOpen(false); 
                } else {
                    skipBlurRef.current = true;
                    addProcess(trimmed);
                    setInputValue(""); 

                    setIsCreating(true); 
                    setIsProcessMenuOpen(true); 

                    setTimeout(() => {
                        if (listRef.current) listRef.current.scrollTop = listRef.current.scrollHeight;
                        if (processInputRef.current) processInputRef.current.focus();
                        skipBlurRef.current = false;
                    }, 50);
                }
            } else {
                setIsCreating(false);
            }
        } else if (e.key === 'Escape') {
            setIsCreating(false);
            setInputValue("");
        }
    };

    const handleInputBlur = () => {
        if (skipBlurRef.current) return;
        if (!inputValue.trim()) {
            setIsCreating(false);
        }
    };

    const handleDeleteClick = (e: React.MouseEvent, id: string, name: string) => {
        e.stopPropagation(); 
        e.preventDefault();

        const process = processes.find(p => p.id === id);
        if (process) {
            const hasEvidence = process.evidence && process.evidence.trim().length > 0;
            const hasMatrix = Object.keys(process.matrixData).some(k => 
                process.matrixData[k].some(r => r.evidenceInput && r.evidenceInput.trim().length > 0)
            );
            const hasFiles = process.uploadedFiles && process.uploadedFiles.length > 0;

            if (hasEvidence || hasMatrix || hasFiles) {
                if (window.confirm(`Delete process "${name}"? \n\n⚠️ WARNING: This process contains evidence/files that will be permanently lost.`)) {
                    deleteProcess(id);
                    showToast(`Deleted: ${name}`);
                }
            } else {
                deleteProcess(id);
                showToast(`Deleted: ${name}`);
            }
        }
    };

    const triggerRename = (p: any) => {
        setEditingProcessId(p.id);
        setEditName(p.name);
    };

    const saveEditing = () => {
        if (editingProcessId && editName.trim()) {
            renameProcess(editingProcessId, editName.trim());
            showToast("Renamed successfully");
        }
        setEditingProcessId(null);
    };

    const displayProcesses = useMemo(() => processes.filter(s => s.name && s.name.trim() !== ""), [processes]);
    const activeProcessName = displayProcesses.find(p => p.id === activeProcessId)?.name || "Select Process";

    return (
        <div className="bg-gray-50/80 dark:bg-slate-900/50 rounded-2xl border border-gray-100 dark:border-slate-800 shadow-sm p-3 space-y-4 w-full">
            <input type="file" ref={fileInputRef} accept=".pdf,.docx,.doc,.txt" className="hidden" onChange={handleFileChange} />

            {/* SECTION 1: STANDARD */}
            <div className="space-y-2">
                <LabelRequired text="Audit Standard" />
                <div className="relative group/source">
                    <IconSelect 
                        id="sidebar-standard-select"
                        icon={sourceIcon}
                        iconColor={`${sourceColor} transition-all duration-300 ${cursorClass}`}
                        value={standardKey} 
                        onChange={(e: any) => { if (e.target.value === "ADD_NEW") onAddNewStandard(); else setStandardKey(e.target.value); }} 
                        options={standardOptions} 
                        defaultText="Select ISO Standard"
                        onIconClick={handleIconClick}
                        iconTitle={sourceTooltip}
                    />

                    {hasSource && (
                        <button
                            onClick={(e) => { e.stopPropagation(); clearKnowledge(); }}
                            className="absolute right-9 top-1/2 -translate-y-1/2 p-1.5 text-slate-400 hover:text-red-500 bg-transparent hover:bg-red-50 dark:hover:bg-red-900/20 rounded-full transition-all z-20 active:scale-95"
                            title="Remove Source File"
                        >
                            <Icon name="Trash2" size={14} />
                        </button>
                    )}

                    {standardKey && (
                        <button onClick={onOpenIntegrity} className={`absolute -top-1.5 -right-1.5 p-1 rounded-full shadow-lg transition-all hover:scale-110 active:scale-95 text-white ring-2 ring-white dark:ring-slate-900 ${health.isHealthy ? 'bg-emerald-500' : 'bg-orange-500'}`} title="Integrity Check">
                            <Icon name={health.isHealthy ? "CheckCircle2" : "AlertCircle"} size={10}/>
                        </button>
                    )}
                </div>

                {/* AUDIT TYPE & TOTAL WD ROW */}
                <div className="flex gap-2 mt-2">
                    <div className="flex-1">
                        <LabelRequired text="Audit Type" />
                        <IconSelect 
                            icon="FileEdit" 
                            iconColor={auditFieldIconColor} 
                            value={auditInfo.type} 
                            onChange={(e: any) => setAuditInfo({...auditInfo, type: e.target.value})} 
                            options={Object.keys(auditTypeOptions).map(key => ({ value: key, label: key }))} 
                            defaultText="Select Type" 
                        />
                    </div>
                    <div className="w-[80px]">
                        <label className="text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase px-1">Total WD</label>
                        <div className="h-11 bg-slate-100 dark:bg-slate-950 border border-gray-200 dark:border-slate-800 rounded-xl flex items-center justify-center text-xs font-mono font-bold text-slate-600 dark:text-slate-300 shadow-inner">
                            {totalManDays}
                        </div>
                    </div>
                </div>
            </div>

            <div className="h-px bg-gray-200 dark:bg-slate-700/50"></div>

            {/* SECTION 2: ENTITY & CONTEXT */}
            <div className="space-y-3">
                <LabelRequired text="Organization Context" />

                {/* Row 1: Company Name (Full Width) */}
                <IconInput icon="Building" iconColor={auditFieldIconColor} placeholder="Company Name" value={auditInfo.company} onChange={(e: any) => setAuditInfo({...auditInfo, company: e.target.value})} />

                {/* Row 2: SMO & Total Sites & Total Employees (Split 50-25-25) */}
                <div className="flex gap-2">
                    <div className="basis-1/2">
                        <IconInput icon="Tag" iconColor={auditFieldIconColor} placeholder="SMO/ID" value={auditInfo.smo} onChange={(e: any) => setAuditInfo({...auditInfo, smo: e.target.value})} />
                    </div>

                    {/* TOTAL SITES INPUT */}
                    <div className="basis-1/4 relative group">
                        <div className="absolute left-2 top-1/2 -translate-y-1/2 pointer-events-none transition-colors duration-300">
                            <div className={auditFieldIconColor}><Icon name="MapPin" size={14} /></div>
                        </div>
                        <input 
                            type="number"
                            placeholder="Sites"
                            title="Total Sites (Auto-Syncs with Logistics)"
                            value={auditSites.length || ""} // Use array length as source of truth for display reactivity
                            onChange={handleTotalSitesChange}
                            className="w-full pl-7 pr-1 h-11 bg-gray-50 dark:bg-slate-950 border border-gray-100 dark:border-slate-800 rounded-xl text-sm font-normal text-slate-700 dark:text-slate-300 placeholder-gray-400 outline-none focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 transition-all shadow-sm hover:border-indigo-200 dark:hover:border-slate-600 hover:shadow-md dark:shadow-[inset_0_2px_4px_rgba(0,0,0,0.5)] [appearance:textfield] [&::-webkit-outer-spin-button]:appearance-none [&::-webkit-inner-spin-button]:appearance-none"
                        />
                    </div>

                    {/* TOTAL EMPLOYEES INPUT */}
                    <div className="basis-1/4 relative group">
                        <div className="absolute left-2 top-1/2 -translate-y-1/2 pointer-events-none transition-colors duration-300">
                            <div className={auditFieldIconColor}><Icon name="Users" size={14} /></div>
                        </div>
                        <input 
                            type="number"
                            placeholder="Staff"
                            title="Total Employees (All Sites)"
                            value={auditInfo.totalEmployees || ""}
                            onChange={(e) => setAuditInfo({...auditInfo, totalEmployees: parseInt(e.target.value) || 0})}
                            className="w-full pl-7 pr-1 h-11 bg-gray-50 dark:bg-slate-950 border border-gray-100 dark:border-slate-800 rounded-xl text-sm font-normal text-slate-700 dark:text-slate-300 placeholder-gray-400 outline-none focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 transition-all shadow-sm hover:border-indigo-200 dark:hover:border-slate-600 hover:shadow-md dark:shadow-[inset_0_2px_4px_rgba(0,0,0,0.5)] [appearance:textfield] [&::-webkit-outer-spin-button]:appearance-none [&::-webkit-inner-spin-button]:appearance-none"
                        />
                    </div>
                </div>

                <IconTextArea 
                    icon="MapPin" 
                    iconColor={auditFieldIconColor} 
                    placeholder="Site Address / Locations..." 
                    value={auditInfo.address || ""} 
                    onChange={(e: any) => setAuditInfo({...auditInfo, address: e.target.value})}
                    rows={2}
                />

                <IconTextArea 
                    icon="Target" 
                    iconColor={auditFieldIconColor} 
                    placeholder="Audit Scope Description..." 
                    value={auditInfo.scope || ""} 
                    onChange={(e: any) => setAuditInfo({...auditInfo, scope: e.target.value})}
                    rows={3}
                />

                {is27001 && (
                    <div className="animate-in fade-in slide-in-from-top-2">
                        <IconInput 
                            icon="FileShield" 
                            iconColor="text-purple-600 dark:text-purple-400" 
                            placeholder="SoA Version / Reference (e.g. v2.0 2024)" 
                            value={auditInfo.soa || ""} 
                            onChange={(e: any) => setAuditInfo({...auditInfo, soa: e.target.value})} 
                        />
                    </div>
                )}

                {/* PROCESS MANAGEMENT DROPDOWN */}
                <div className="space-y-2 pt-1">
                    <div className="flex justify-between items-center px-1">
                        <label className="text-[10px] font-bold text-indigo-500 dark:text-indigo-400 uppercase">
                            Process Management <span className="text-red-500" title="Required Field">*</span>
                        </label>
                        <span className="text-[9px] text-slate-400 dark:text-slate-500 font-mono">{displayProcesses.length} Items</span>
                    </div>

                    {displayProcesses.length === 0 ? (
                        <>
                            <div className="relative group w-full">
                                <div className="absolute left-3 top-1/2 -translate-y-1/2 pointer-events-none text-indigo-600 dark:text-indigo-400 group-focus-within:text-indigo-500">
                                    <Icon name="Plus" size={16} />
                                </div>
                                <input
                                    ref={processInputRef}
                                    type="text"
                                    value={inputValue}
                                    placeholder="Enter Process/Department..."
                                    onChange={(e) => setInputValue(e.target.value)}
                                    onKeyDown={handleAddKeyDown}
                                    className="w-full pl-10 pr-3 h-11 bg-white dark:bg-slate-950 border border-indigo-100 dark:border-slate-700 rounded-xl text-xs font-bold text-slate-700 dark:text-slate-300 placeholder-indigo-300 dark:placeholder-slate-600 outline-none focus:border-indigo-500 focus:ring-2 focus:ring-indigo-500/10 transition-all shadow-sm"
                                    autoComplete="off"
                                />
                            </div>
                        </>
                    ) : (
                        <div className="relative">
                            <div 
                                onClick={() => { if(!isCreating) setIsProcessMenuOpen(!isProcessMenuOpen); }}
                                className={`w-full h-11 flex items-center justify-between px-3 rounded-xl border cursor-pointer transition-all duration-200 ${
                                    isProcessMenuOpen || isCreating 
                                        ? 'border-indigo-500 ring-1 ring-indigo-500 bg-white dark:bg-slate-900 shadow-md z-20' 
                                        : 'bg-white dark:bg-slate-900 border-gray-100 dark:border-slate-800 hover:border-indigo-300 dark:hover:border-slate-700'
                                }`}
                            >
                                <div className="flex items-center gap-3 overflow-hidden flex-1">
                                    <Icon name="Session11_GridAdd" size={16} className="text-indigo-600 dark:text-indigo-400" />
                                    {isCreating ? (
                                        <input
                                            ref={processInputRef}
                                            autoFocus
                                            value={inputValue}
                                            onChange={e => setInputValue(e.target.value)}
                                            onKeyDown={handleAddKeyDown}
                                            onBlur={handleInputBlur}
                                            placeholder="Type Name & Enter to Add..."
                                            className="bg-transparent border-none outline-none text-xs font-bold text-slate-800 dark:text-white placeholder-slate-400 w-full"
                                            onClick={(e) => e.stopPropagation()}
                                            autoComplete="off"
                                        />
                                    ) : (
                                        <span className="text-xs font-bold truncate text-slate-700 dark:text-slate-300">
                                            {activeProcessName}
                                        </span>
                                    )}
                                </div>

                                <div className="flex items-center gap-2">
                                    {!isCreating && (
                                        <div 
                                            className={`p-1 rounded-full ${isProcessMenuOpen ? 'bg-indigo-100 text-indigo-600 dark:bg-slate-800 dark:text-indigo-400' : 'hover:bg-gray-100 dark:hover:bg-slate-800 text-slate-400'}`} 
                                            title="Add New Process"
                                            onClick={(e) => {
                                                e.stopPropagation();
                                                setIsProcessMenuOpen(true);
                                                setIsCreating(true);
                                                setInputValue("");
                                                setTimeout(() => processInputRef.current?.focus(), 50);
                                            }}
                                        >
                                            <Icon name="Plus" size={14} />
                                        </div>
                                    )}
                                    {isCreating && (
                                        <div 
                                            className="p-1 rounded-full hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-400 hover:text-red-500" 
                                            title="Cancel / Close"
                                            onClick={(e) => {
                                                e.stopPropagation();
                                                setIsCreating(false);
                                                setInputValue("");
                                            }}
                                        >
                                            <Icon name="X" size={14} />
                                        </div>
                                    )}
                                    <Icon name="ChevronDown" size={14} className={`transition-transform duration-300 text-slate-400 ${isProcessMenuOpen ? 'rotate-180' : ''}`} />
                                </div>
                            </div>

                            <div className={`overflow-hidden transition-all duration-300 ease-in-out ${isProcessMenuOpen ? 'max-h-[300px] opacity-100 mt-2' : 'max-h-0 opacity-0'}`}>
                                <div className="p-1 bg-white dark:bg-slate-950 border border-gray-200 dark:border-slate-800 rounded-xl shadow-xl space-y-1">
                                    <div ref={listRef} className="max-h-[200px] overflow-y-auto custom-scrollbar px-1 space-y-1 pb-1 pt-1 scroll-smooth">
                                        {displayProcesses.map(p => {
                                            const isActive = activeProcessId === p.id;
                                            const isEditing = editingProcessId === p.id;

                                            return (
                                                <div 
                                                    key={p.id}
                                                    className={`group flex items-center justify-between p-2 rounded-lg cursor-pointer transition-all ${isActive ? 'bg-indigo-50 dark:bg-indigo-900/20 border border-indigo-100 dark:border-indigo-900/30' : 'hover:bg-gray-50 dark:hover:bg-slate-800 border border-transparent'}`}
                                                    onClick={() => {
                                                        if(!isEditing) {
                                                            setActiveProcessId(p.id);
                                                            if (!isCreating) setIsProcessMenuOpen(false); 
                                                        }
                                                    }}
                                                >
                                                    <div className="flex items-center gap-2 overflow-hidden flex-1">
                                                        <div className={`w-1.5 h-1.5 rounded-full flex-shrink-0 ${isActive ? 'bg-indigo-500' : 'bg-slate-300 dark:bg-slate-700'}`}></div>

                                                        {isEditing ? (
                                                            <input 
                                                                autoFocus
                                                                className="w-full min-w-0 bg-white dark:bg-slate-900 text-slate-900 dark:text-white text-xs font-bold px-1 py-0.5 rounded outline-none border border-indigo-300"
                                                                value={editName}
                                                                onChange={e => setEditName(e.target.value)}
                                                                onKeyDown={e => e.key === 'Enter' && saveEditing()}
                                                                onBlur={saveEditing}
                                                                onClick={e => e.stopPropagation()} 
                                                            />
                                                        ) : (
                                                            <span className={`text-xs truncate font-bold ${isActive ? 'text-indigo-700 dark:text-indigo-300' : 'text-slate-600 dark:text-slate-400'}`}>
                                                                {p.name}
                                                            </span>
                                                        )}
                                                    </div>

                                                    {!isEditing && (
                                                        <div className="flex items-center gap-1 opacity-100 md:opacity-0 md:group-hover:opacity-100 transition-opacity">
                                                            <button 
                                                                type="button"
                                                                onClick={(e) => { e.preventDefault(); e.stopPropagation(); triggerRename(p); }}
                                                                className="p-1.5 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 dark:hover:bg-indigo-900/20 rounded-md"
                                                                title="Rename"
                                                            >
                                                                <Icon name="FileEdit" size={12}/>
                                                            </button>

                                                            <button 
                                                                type="button"
                                                                onClick={(e) => handleDeleteClick(e, p.id, p.name)}
                                                                className="p-1.5 text-slate-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-md"
                                                                title="Delete"
                                                            >
                                                                <Icon name="Trash2" size={12}/>
                                                            </button>
                                                        </div>
                                                    )}
                                                </div>
                                            );
                                        })}
                                    </div>
                                </div>
                            </div>
                        </div>
                    )}
                </div>
            </div>

            <div className="h-px bg-gray-200 dark:bg-slate-700/50"></div>

            {/* SECTION 3: PERSONNEL */}
            <div className="space-y-2">
                <LabelRequired text="Auditor" />
                <div className="flex gap-2">
                     <div className="flex-1">
                        <IconInput icon="AuditUser" iconColor={auditFieldIconColor} placeholder="Lead Auditor Name" value={auditInfo.auditor} onChange={(e: any) => setAuditInfo({...auditInfo, auditor: e.target.value})} />
                     </div>
                     <div className="w-[100px]">
                        <IconInput icon="Tag" iconColor={auditFieldIconColor} placeholder="CODE" value={auditInfo.leadAuditorCode || ""} onChange={(e: any) => setAuditInfo({...auditInfo, leadAuditorCode: e.target.value})} />
                     </div>
                </div>
            </div>
        </div>
    );
};

import React, { useState, useMemo, useRef, memo, useCallback, useEffect } from 'react';
import { Icon, GlassDatePicker, Modal } from '../UI';
import { useAudit } from '../../contexts/AuditContext';
import { Clause, AuditMember, AuditSite } from '../../types';
import { useUI } from '../../contexts/UIContext';
import { useKeyPool } from '../../contexts/KeyPoolContext';
import { cleanAndParseJSON } from '../../utils';
import { TABS_CONFIG } from '../../constants';
import { generateAuditSchedule } from '../../services/geminiService';

// --- INTERNAL TYPES ---
interface PlanningRowProps {
    clause: Clause;
    level: number;
    processes: any[];
    onSmartToggle: (procId: string, clause: Clause) => void; 
}

interface PlanningViewProps {
    onExport?: (type: 'schedule', lang: 'en' | 'vi', format?: 'txt' | 'docx', extraData?: any) => void;
}

// --- HELPER: Get all descendant IDs ---
const getFlatClauseIds = (clause: Clause): string[] => {
    let ids = [clause.id];
    if (clause.subClauses) {
        clause.subClauses.forEach(sub => {
            ids = [...ids, ...getFlatClauseIds(sub)];
        });
    }
    return ids;
};

// --- MEMOIZED MATRIX ROW COMPONENT ---
const PlanningRow = memo(({ 
    clause, level, processes, onSmartToggle 
}: PlanningRowProps) => {

    const selfAndDescendants = useMemo(() => getFlatClauseIds(clause), [clause]);
    const isParent = clause.subClauses && clause.subClauses.length > 0;

    return (
        <tr className="hover:bg-gray-50 dark:hover:bg-slate-800/30 transition-colors group duration-300 ease-fluid">
            <td className="p-2 border-r border-gray-100 dark:border-slate-800 sticky left-0 bg-white dark:bg-slate-900 group-hover:bg-gray-50 dark:group-hover:bg-slate-800/30 z-10 align-top transition-colors duration-300 ease-fluid">
                <div className={`flex flex-col gap-1 ${level > 0 ? 'ml-4 border-l-2 border-gray-200 dark:border-slate-800 pl-2' : ''}`}>
                    <div className="flex items-center gap-2">
                        <span className={`px-1.5 py-0.5 rounded text-[10px] font-bold whitespace-nowrap ${level === 0 ? 'bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-400 border border-slate-200 dark:border-slate-700' : 'text-slate-400'}`}>
                            {clause.code}
                        </span>
                        <span className={`text-xs truncate ${level === 0 ? 'font-bold text-slate-800 dark:text-slate-200' : 'font-medium text-slate-600 dark:text-slate-400'}`}>
                            {clause.title}
                        </span>
                    </div>
                </div>
            </td>
            {processes.map(p => {
                let status: 'all' | 'some' | 'none' = 'none';

                if (isParent) {
                    const activeCount = selfAndDescendants.reduce((acc, id) => acc + (p.matrixData[id] ? 1 : 0), 0);
                    if (activeCount === selfAndDescendants.length) status = 'all';
                    else if (activeCount > 0) status = 'some';
                } else {
                    status = p.matrixData[clause.id] ? 'all' : 'none';
                }

                return (
                    <td key={`${p.id}_${clause.id}`} className="p-1 text-center border-r border-gray-50 dark:border-slate-800/50 last:border-0 relative align-middle">
                        <div className="flex justify-center">
                            <button
                                onClick={() => onSmartToggle(p.id, clause)}
                                className={`w-8 h-8 rounded-lg flex items-center justify-center transition-all duration-300 ease-spring ${
                                    status === 'all' 
                                        ? 'bg-emerald-500 text-white shadow-sm shadow-emerald-500/40 transform scale-105' 
                                        : status === 'some'
                                            ? 'bg-orange-100 dark:bg-orange-900/30 text-orange-500 border border-orange-200 dark:border-orange-800'
                                            : 'bg-slate-50 dark:bg-slate-800/50 hover:bg-slate-200 dark:hover:bg-slate-700 text-slate-300'
                                }`}
                                title={status === 'all' ? "Fully Planned" : status === 'some' ? "Partially Planned (Click to Fill)" : "Click to Plan"}
                            >
                                {status === 'all' && (isParent ? <Icon name="CheckCircle2" size={14}/> : <Icon name="CheckThick" size={14}/>)}
                                {status === 'some' && <div className="w-2.5 h-2.5 rounded-full bg-orange-500"></div>}
                            </button>
                        </div>
                    </td>
                );
            })}
        </tr>
    );
}, (prev, next) => {
    if (prev.processes.length !== next.processes.length) return false;

    // Deep check to prevent re-render unless matrix data actually changed for this row
    const hasChange = prev.processes.some((pp, idx) => {
        const np = next.processes[idx];
        return pp.matrixData !== np.matrixData;
    });

    return !hasChange; 
});


export const PlanningView: React.FC<PlanningViewProps> = ({ onExport }) => {
