            // Since we render from sorted array, we need a robust way. 
            // Simpler: The `reassignTarget` should ideally store the ID or unique ref.
            // For now, let's update by index passed from the sorted view which is risky.
            // BETTER: pass the actual item object from the render loop.
            return newSchedule; 
        });

        // Wait, the state `auditSchedule` is flat. The view is grouped.
        // Let's change the handler to accept the schedule item index in the main array.
    };

    // Corrected Handler using Item Reference
    const updateScheduleItem = (itemIndex: number, field: string, value: any) => {
